Javascript.validate:
var val = Services.getValue(AmountOrdered.dataBinding);
var err = validateCurrencyValue(val, 999999.99);
if( null == err ) {
	var fVal = WPU.formatToTwoDP(val);
	Services.setValue(AmountOrdered.dataBinding, fVal);	}
return err;

