Javascript.miscCode:
function DefaultCurrency330() {}
DefaultCurrency330.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency330.tabIndex = -1;
DefaultCurrency330.maxLength = 1;
DefaultCurrency330.isReadOnly = function(){return true;}
DefaultCurrency330.isTemporary = function(){return true;}
DefaultCurrency330.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency330.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
